            "project": "cumpleanos-peuhen",
            "section": 1,
            "title": "El cumpleaños de Peuhen en España",
            "titleEn": "Pehuen’s birthday in Spain",
            "director": "Federico Luis ",
            "producer": "Jerónimo Quevedo",
            "image": "elcumpleaños_lp.png",
